import { Link } from 'react-router-dom';

function Navbar() {
  return (
    <nav>
      <h6><Link to="/home">Jueun Jeon</Link></h6>
      <p><Link to="/home">Home</Link></p>
      <p><Link to="/about">About</Link></p>
    </nav>
  );
}

export default Navbar;
